// Parse the AI's advice, then apply the DETERMINISTIC GATE (no AI here).
// supplier/qty/price are COMPUTED — never taken from the model.
const signals = $('Mock Demand Signals').item.json;

// 1. Extract the AI advice text (Anthropic returns content[].text) and parse JSON.
let advice = { confidence: 0, decision: 'escalate', rationale: 'no/invalid AI response (fail-closed)' };
try {
  const raw = $json.content?.[0]?.text ?? $json.text ?? '';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (typeof parsed.confidence === 'number' && parsed.decision) advice = parsed;
} catch (e) { /* fail closed: keep the escalate default */ }

// 2. Deterministic quantity: max(net_need, MOQ), rounded up to a whole MOQ multiple.
const moq = signals.moq || 1;
let qty = Math.max(signals.net_need || 0, moq);
if (moq > 1) qty = Math.ceil(qty / moq) * moq;
const bundle_total = qty * (signals.unit_price || 0);

// 3. The GATE the AI cannot override.
let verdict;
if (advice.decision === 'escalate') verdict = 'escalate';
else if (advice.confidence < signals.confidence_floor) verdict = 'stage';      // below confidence floor -> human
else if (bundle_total > signals.spend_cap) verdict = 'stage';                  // over spend cap -> human
else if (advice.decision === 'act') verdict = 'auto_place';                    // clears every check
else verdict = 'stage';                                                        // 'recommend' -> human

return [{ json: {
  sku: signals.sku,
  product: signals.product_name,
  supplier: signals.supplier,             // from sourcing, not the model
  qty,                                    // computed
  unit_price: signals.unit_price,         // from contract, not the model
  bundle_total,                           // computed
  ai_confidence: advice.confidence,
  ai_decision: advice.decision,
  ai_rationale: advice.rationale,
  gate_verdict: verdict,
  decided_at: $now.toISO()
}}];
